import React from 'react';
import { Menu } from 'antd';
import { MenuItem } from '../../Layout/app/Types';
import { menuData } from './MenuItemsData';

const { SubMenu } = Menu;

const generateMenuItems = (items: MenuItem[]): React.ReactNode => {
  return items.map((item) => {
    if (item.megaChildren) {
      const rows = 4;
      const columns = 3;
      const itemsPerRow = Math.ceil(item.megaChildren.length / rows);

      const megaGroups = Array.from({ length: columns }, (_, colIndex) => (
        <Menu.ItemGroup key={`${item.key}_col${colIndex + 1}`} title={`Column ${colIndex + 1}`}>
          {item.megaChildren.slice(colIndex * itemsPerRow, (colIndex + 1) * itemsPerRow).map((megaItem) => (
            <Menu.Item key={megaItem.key}>
              <a href={`/${megaItem.key}`}>{megaItem.label}</a>
            </Menu.Item>
          ))}
        </Menu.ItemGroup>
      ));

      return (
        <SubMenu key={item.key} icon={item.icon} title={item.label}>
          {megaGroups}
        </SubMenu>
      );
    } else {
      return (
        <Menu.Item key={item.key}>
          <a href={`/${item.key}`}>{item.label}</a>
        </Menu.Item>
      );
    }
  });
};

const MenuItems: React.FC<{ items: MenuItem[] }> = ({ items }) => {
  return <Menu mode="vertical">{generateMenuItems(items)}</Menu>;
};

const App = () => {
  return <MenuItems items={menuData} />;
};

export default App;
